internal class FfiException: UniffiException {
    FfiException(string message): base(message) {}

    // Each variant is a nested class
    // Flat enums carries a string error message, so no special implementation is necessary.
    
    public class Database: FfiException {
        public Database(string message): base(message) {}
    }
    
    public class NotFound: FfiException {
        public NotFound(string message): base(message) {}
    }
    
    public class InvalidId: FfiException {
        public InvalidId(string message): base(message) {}
    }
    
    public class Io: FfiException {
        public Io(string message): base(message) {}
    }
    
    public class Other: FfiException {
        public Other(string message): base(message) {}
    }
    
}

class FfiConverterTypeFfiError : FfiConverterRustBuffer<FfiException>, CallStatusErrorHandler<FfiException> {
    public static FfiConverterTypeFfiError INSTANCE = new FfiConverterTypeFfiError();

    public override FfiException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1: return new FfiException.Database(FfiConverterString.INSTANCE.Read(stream));
            case 2: return new FfiException.NotFound(FfiConverterString.INSTANCE.Read(stream));
            case 3: return new FfiException.InvalidId(FfiConverterString.INSTANCE.Read(stream));
            case 4: return new FfiException.Io(FfiConverterString.INSTANCE.Read(stream));
            case 5: return new FfiException.Other(FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeFfiError.Read()", value));
        }
    }

    public override int AllocationSize(FfiException value) {
        return 4 + FfiConverterString.INSTANCE.AllocationSize(value.Message);
    }

    public override void Write(FfiException value, BigEndianStream stream) {
        switch (value) {
            case FfiException.Database:
                stream.WriteInt(1);
                break;
            case FfiException.NotFound:
                stream.WriteInt(2);
                break;
            case FfiException.InvalidId:
                stream.WriteInt(3);
                break;
            case FfiException.Io:
                stream.WriteInt(4);
                break;
            case FfiException.Other:
                stream.WriteInt(5);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeFfiError.Write()", value));
        }
    }
}





